// Validate input and set defaults
const input = $input.first().json;

// Validate prompt
const prompt = (input.prompt || '').toString().trim();
if (!prompt) {
  throw new Error('Missing required field: prompt');
}
if (prompt.length > 2000) {
  throw new Error('Prompt too long: max 2000 characters');
}

// Validate dimensions
const width = Math.min(Math.max(parseInt(input.width) || 1024, 256), 2048);
const height = Math.min(Math.max(parseInt(input.height) || 1024, 256), 2048);
const steps = Math.min(Math.max(parseInt(input.steps) || 20, 1), 50);
const cfg = Math.min(Math.max(parseFloat(input.cfg) || 8.0, 1.0), 30.0);
const seed = parseInt(input.seed) || Math.floor(Math.random() * 9999999999);

return [{
  json: {
    prompt: prompt,
    width: width,
    height: height,
    steps: steps,
    cfg: cfg,
    seed: seed,
    channel: input.channel || '#general',
    model: ($env.COMFYUI_MODEL || 'flux1-dev.safetensors').toString()
  }
}];

// Process ComfyUI response
const body = $input.first().json || {};
const webhookInput = $('Validate Input').first().json || {};

const promptId = body.prompt_id || 'unknown';
const number = body.number || 0;

return [{
  json: {
    success: !!promptId && promptId !== 'unknown',
    prompt_id: promptId,
    queue_number: number,
    timestamp: new Date().toISOString(),
    channel: webhookInput.channel || '#general',
    prompt: webhookInput.prompt || '',
    width: webhookInput.width || 1024,
    height: webhookInput.height || 1024,
    steps: webhookInput.steps || 20,
    cfg: webhookInput.cfg || 8.0,
    seed: webhookInput.seed || 'random'
  }
}];
